+/**
+ * Notification log model for tracking sent notification history.
+ *
+ * Each log entry captures the full context of a notification dispatch:
+ * who received it, through which channel, what type, when it was sent,
+ * and whether delivery succeeded.
+ */
+
+import type { NotificationChannel, NotificationType } from './notification.js';
+
+/**
+ * Delivery status of a notification.
+ */
+export type DeliveryStatus = 'sent' | 'delivered' | 'failed';
+
+/**
+ * A persisted record of a sent notification, used for history tracking.
+ */
+export interface NotificationLog {
+  id: string;
+  notificationId: string;
+  recipient: string;
+  channel: NotificationChannel;
+  notificationType: NotificationType;
+  subject: string;
+  body: string;
+  status: DeliveryStatus;
+  sentAt: Date;
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Filters for querying notification history.
+ */
+export interface NotificationLogQuery {
+  recipient?: string;
+  notificationType?: NotificationType;
+  channel?: NotificationChannel;
+  status?: DeliveryStatus;
+  startDate?: Date;
+  endDate?: Date;
+}

