+/**
+ * Notification history service — tracks and queries sent notification logs.
+ *
+ * This service is responsible for:
+ * - Logging every dispatched notification with its delivery status
+ * - Providing query capabilities for notification history
+ *
+ * Integration:
+ *   The NotificationService calls `logNotification()` after each dispatch.
+ *   This keeps the history service as a passive recorder that does not
+ *   interfere with the notification delivery flow.
+ *
+ * Depends on:
+ *   - NotificationLogRepository for data persistence
+ */
+
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type {
+  NotificationLog,
+  NotificationLogQuery,
+  DeliveryStatus,
+} from '../models/notification-log.js';
+import type { Notification } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generateLogId(): string {
+  return `log-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetLogIdCounter(): void {
+  nextId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a sent notification with its delivery status.
+   */
+  logNotification(notification: Notification, status: DeliveryStatus): NotificationLog {
+    const logEntry: NotificationLog = {
+      id: generateLogId(),
+      notificationId: notification.id,
+      recipient: notification.recipient,
+      channel: notification.channel,
+      notificationType: notification.notificationType,
+      subject: notification.subject,
+      body: notification.body,
+      status,
+      sentAt: notification.sentAt,
+      metadata: notification.metadata,
+    };
+
+    this.repository.save(logEntry);
+    this.logger.info(`Logged notification ${notification.id} with status: ${status}`);
+    return logEntry;
+  }
+
+  /**
+   * Get all notification log entries.
+   */
+  getLogs(): NotificationLog[] {
+    return this.repository.findAll();
+  }
+
+  /**
+   * Get a notification log entry by ID.
+   */
+  getLogById(id: string): NotificationLog | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get notification history for a specific recipient.
+   */
+  getLogsByRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get notification history by notification type.
+   */
+  getLogsByType(notificationType: NotificationLog['notificationType']): NotificationLog[] {
+    return this.repository.findByType(notificationType);
+  }
+
+  /**
+   * Get notification history by channel.
+   */
+  getLogsByChannel(channel: NotificationLog['channel']): NotificationLog[] {
+    return this.repository.findByChannel(channel);
+  }
+
+  /**
+   * Query notification history with multiple filters.
+   */
+  queryLogs(filters: NotificationLogQuery): NotificationLog[] {
+    return this.repository.query(filters);
+  }
+
+  /**
+   * Get the total count of logged notifications.
+   */
+  getLogCount(): number {
+    return this.repository.count();
+  }
+}

