import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * Delivery status of a notification.
 */
export type DeliveryStatus = 'sent' | 'delivered' | 'failed';

/**
 * A persisted record of a sent notification, used for history tracking.
 */
export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Filters for querying notification history.
 */
export interface NotificationLogQuery {
  recipient?: string;
  notificationType?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, NotificationLogQuery } from '../models/notification-log.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      notificationType: record['notificationType'] as NotificationType,
      subject: record['subject'] as string,
      body: record['body'] as string,
      status: record['status'] as DeliveryStatus,
      sentAt: new Date(record['sentAt'] as string),
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) as Record<string, unknown> : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      notificationType: entity.notificationType,
      subject: entity.subject,
      body: entity.body,
      status: entity.status,
      sentAt: entity.sentAt.toISOString(),
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
    };
  }

  /**
   * Find log entries by recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find log entries by notification type.
   */
  findByType(notificationType: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.notificationType === notificationType);
  }

  /**
   * Find log entries by channel.
   */
  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  /**
   * Query log entries with multiple filters.
   */
  query(filters: NotificationLogQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.notificationType && log.notificationType !== filters.notificationType) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.startDate && log.sentAt < filters.startDate) return false;
      if (filters.endDate && log.sentAt > filters.endDate) return false;
      return true;
    });
  }
}

/**
 * Notification history service — tracks and queries sent notification logs.
 *
 * This service is responsible for:
 * - Logging every dispatched notification with its delivery status
 * - Providing query capabilities for notification history
 *
 * Integration:
 *   The NotificationService calls `logNotification()` after each dispatch.
 *   This keeps the history service as a passive recorder that does not
 *   interfere with the notification delivery flow.
 *
 * Depends on:
 *   - NotificationLogRepository for data persistence
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type {
  NotificationLog,
  NotificationLogQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { Notification } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `log-${String(nextId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a sent notification with its delivery status.
   */
  logNotification(notification: Notification, status: DeliveryStatus): NotificationLog {
    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      notificationType: notification.notificationType,
      subject: notification.subject,
      body: notification.body,
      status,
      sentAt: notification.sentAt,
      metadata: notification.metadata,
    };

    this.repository.save(logEntry);
    this.logger.info(`Logged notification ${notification.id} with status: ${status}`);
    return logEntry;
  }

  /**
   * Get all notification log entries.
   */
  getLogs(): NotificationLog[] {
    return this.repository.findAll();
  }

  /**
   * Get a notification log entry by ID.
   */
  getLogById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get notification history for a specific recipient.
   */
  getLogsByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get notification history by notification type.
   */
  getLogsByType(notificationType: NotificationLog['notificationType']): NotificationLog[] {
    return this.repository.findByType(notificationType);
  }

  /**
   * Get notification history by channel.
   */
  getLogsByChannel(channel: NotificationLog['channel']): NotificationLog[] {
    return this.repository.findByChannel(channel);
  }

  /**
   * Query notification history with multiple filters.
   */
  queryLogs(filters: NotificationLogQuery): NotificationLog[] {
    return this.repository.query(filters);
  }

  /**
   * Get the total count of logged notifications.
   */
  getLogCount(): number {
    return this.repository.count();
  }
}

