import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body',
    channel: 'email',
    notificationType: 'order_confirmation',
    sentAt: new Date('2026-01-15T10:00:00Z'),
    metadata: { userId: 'user-1' },
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a notification with delivery status', () => {
      const notification = makeNotification();
      const log = historyService.logNotification(notification, 'delivered');

      expect(log.id).toBe('log-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.notificationType).toBe('order_confirmation');
      expect(log.subject).toBe('Test Subject');
      expect(log.body).toBe('Test body');
      expect(log.status).toBe('delivered');
      expect(log.sentAt).toEqual(new Date('2026-01-15T10:00:00Z'));
      expect(log.metadata).toEqual({ userId: 'user-1' });
    });

    it('should generate sequential log IDs', () => {
      const log1 = historyService.logNotification(makeNotification({ id: 'notif-0001' }), 'delivered');
      const log2 = historyService.logNotification(makeNotification({ id: 'notif-0002' }), 'failed');

      expect(log1.id).toBe('log-0001');
      expect(log2.id).toBe('log-0002');
    });

    it('should persist the log entry in the repository', () => {
      historyService.logNotification(makeNotification(), 'delivered');

      expect(repository.count()).toBe(1);
      const stored = repository.findById('log-0001');
      expect(stored).toBeDefined();
      expect(stored?.recipient).toBe('alice@example.com');
    });

    it('should log failed notifications', () => {
      const log = historyService.logNotification(makeNotification(), 'failed');

      expect(log.status).toBe('failed');
    });

    it('should log sent notifications (no adapter)', () => {
      const log = historyService.logNotification(makeNotification(), 'sent');

      expect(log.status).toBe('sent');
    });
  });

  describe('getLogs', () => {
    it('should return all log entries', () => {
      historyService.logNotification(makeNotification({ id: 'notif-0001' }), 'delivered');
      historyService.logNotification(makeNotification({ id: 'notif-0002' }), 'delivered');

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(2);
    });

    it('should return empty array when no logs exist', () => {
      expect(historyService.getLogs()).toHaveLength(0);
    });
  });

  describe('getLogById', () => {
    it('should return a log entry by ID', () => {
      historyService.logNotification(makeNotification(), 'delivered');

      const log = historyService.getLogById('log-0001');
      expect(log).toBeDefined();
      expect(log?.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent ID', () => {
      expect(historyService.getLogById('log-9999')).toBeUndefined();
    });
  });

  describe('getLogsByRecipient', () => {
    it('should filter logs by recipient', () => {
      historyService.logNotification(makeNotification({ id: 'notif-0001', recipient: 'alice@example.com' }), 'delivered');
      historyService.logNotification(makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }), 'delivered');
      historyService.logNotification(makeNotification({ id: 'notif-0003', recipient: 'alice@example.com' }), 'delivered');

      const aliceLogs = historyService.getLogsByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(2);
      expect(aliceLogs.every((l) => l.recipient === 'alice@example.com')).toBe(true);

      const bobLogs = historyService.getLogsByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
    });

    it('should return empty array for unknown recipient', () => {
      expect(historyService.getLogsByRecipient('unknown@example.com')).toHaveLength(0);
    });
  });

  describe('getLogsByType', () => {
    it('should filter logs by notification type', () => {
      historyService.logNotification(makeNotification({ id: 'notif-0001', notificationType: 'order_confirmation' }), 'delivered');
      historyService.logNotification(makeNotification({ id: 'notif-0002', notificationType: 'user_welcome' }), 'delivered');

      const orderLogs = historyService.getLogsByType('order_confirmation');
      expect(orderLogs).toHaveLength(1);
      expect(orderLogs[0]?.notificationType).toBe('order_confirmation');
    });
  });

  describe('getLogsByChannel', () => {
    it('should filter logs by channel', () => {
      historyService.logNotification(makeNotification({ id: 'notif-0001', channel: 'email' }), 'delivered');
      historyService.logNotification(makeNotification({ id: 'notif-0002', channel: 'webhook' }), 'delivered');

      const emailLogs = historyService.getLogsByChannel('email');
      expect(emailLogs).toHaveLength(1);
      expect(emailLogs[0]?.channel).toBe('email');
    });
  });

  describe('queryLogs', () => {
    beforeEach(() => {
      historyService.logNotification(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          notificationType: 'order_confirmation',
          channel: 'email',
          sentAt: new Date('2026-01-10T10:00:00Z'),
        }),
        'delivered',
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          notificationType: 'user_welcome',
          channel: 'email',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        }),
        'delivered',
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          notificationType: 'order_status_update',
          channel: 'webhook',
          sentAt: new Date('2026-01-20T10:00:00Z'),
        }),
        'failed',
      );
    });

    it('should filter by recipient', () => {
      const logs = historyService.queryLogs({ recipient: 'alice@example.com' });
      expect(logs).toHaveLength(2);
    });

    it('should filter by notification type', () => {
      const logs = historyService.queryLogs({ notificationType: 'order_confirmation' });
      expect(logs).toHaveLength(1);
    });

    it('should filter by channel', () => {
      const logs = historyService.queryLogs({ channel: 'webhook' });
      expect(logs).toHaveLength(1);
    });

    it('should filter by status', () => {
      const logs = historyService.queryLogs({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0003');
    });

    it('should filter by date range', () => {
      const logs = historyService.queryLogs({
        startDate: new Date('2026-01-12T00:00:00Z'),
        endDate: new Date('2026-01-18T00:00:00Z'),
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0002');
    });

    it('should combine multiple filters', () => {
      const logs = historyService.queryLogs({
        recipient: 'alice@example.com',
        channel: 'email',
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationType).toBe('order_confirmation');
    });

    it('should return all logs with empty filters', () => {
      const logs = historyService.queryLogs({});
      expect(logs).toHaveLength(3);
    });
  });

  describe('getLogCount', () => {
    it('should return zero when no logs exist', () => {
      expect(historyService.getLogCount()).toBe(0);
    });

    it('should return the correct count', () => {
      historyService.logNotification(makeNotification({ id: 'notif-0001' }), 'delivered');
      historyService.logNotification(makeNotification({ id: 'notif-0002' }), 'delivered');

      expect(historyService.getLogCount()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications sent without an adapter as "sent"', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.notificationType).toBe('user_welcome');
    });

    it('should log notifications delivered via adapter as "delivered"', async () => {
      const emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);
      // Allow async adapter delivery to complete
      await new Promise((resolve) => setTimeout(resolve, 10));

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('delivered');
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.channel).toBe('email');
    });

    it('should track multiple notifications from different events', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(2);

      const aliceLogs = historyService.getLogsByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);

      const bobLogs = historyService.getLogsByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
    });
  });
});
